{
  "$schema": "https://metaharness.dev/schemas/mcp-policy/v1.json",
  "_comment": "@metaharness/example-iot — default-deny IoT fleet inspection policy. Mutations are not granted here; pass --allow-mutations to the harness CLI to unlock write tools.",

  "defaultDeny": true,
  "mutations_require_flag": "--allow-mutations",

  "allowNetwork": false,
  "allowShell": false,
  "allowFileWrite": false,

  "requireApprovalForDangerous": true,
  "toolTimeoutMs": 15000,
  "maxToolCallsPerTurn": 10,

  "auditLog": true,
  "auditLogPath": ".harness/audit/iot-mcp-audit.jsonl",

  "grantedTools": [
    {
      "tool": "iot.device_list",
      "description": "List registered devices in the fleet. Read-only.",
      "risk": "none"
    },
    {
      "tool": "iot.device_status",
      "description": "Fetch the current connection + error state of a single device. Read-only.",
      "risk": "none"
    },
    {
      "tool": "iot.telemetry_read",
      "description": "Retrieve the last N telemetry samples for a device (temperature, humidity, RSSI, uptime). Read-only.",
      "risk": "none"
    },
    {
      "tool": "iot.config_read",
      "description": "Read the current firmware config blob for a device. Read-only; does not push any change.",
      "risk": "none"
    },
    {
      "tool": "iot.heartbeat_check",
      "description": "Check when a device last sent a heartbeat and whether it is within the expected interval. Read-only.",
      "risk": "none"
    }
  ],

  "deniedTools": [
    {
      "tool": "iot.config_push",
      "reason": "Mutates device firmware config. Requires --allow-mutations."
    },
    {
      "tool": "iot.command_send",
      "reason": "Sends an arbitrary command to a device. Requires --allow-mutations."
    },
    {
      "tool": "iot.ota_trigger",
      "reason": "Initiates an over-the-air firmware update. Requires --allow-mutations."
    },
    {
      "tool": "iot.device_reset",
      "reason": "Resets a device to factory state. Requires --allow-mutations."
    },
    {
      "tool": "iot.fleet_deregister",
      "reason": "Removes a device from the fleet registry. Requires --allow-mutations."
    }
  ],

  "sandboxOverride": {
    "_comment": "When IOT_SANDBOX_MODE=true all iot.* calls are routed to the sandbox endpoint; no real devices are touched regardless of this policy.",
    "envVar": "IOT_SANDBOX_MODE",
    "value": "true",
    "effect": "redirect_to_sandbox"
  }
}
